%% =========================================================================
% sum_session_effect_comparison.m
%
% Purpose:
% Summarize effect-comparison results across sessions.
%
% This script reads the per-session comparison_summary files generated by:
%   size_effect_comparation.m
%   contrast_effect_comparation.m
%
% It makes three summary figures:
%
%   Figure 1:
%       slope summary across sessions
%       Each comparison has one distribution per group.
%       Each point is one session.
%
%   Figure 2:
%       delta summary for baseline metric >= 0
%       Each comparison contains group blocks.
%       Within each group, each session is drawn separately.
%       Each distribution contains unit-level delta values.
%
%   Figure 3:
%       delta summary for baseline metric < 0
%       Same layout as Figure 2.
%
% Folder rule:
%
%   root_dir
%       session_folder
%           catgt_*
%               FA_Dlag_<data_content>
%                   mat_results
%                       runXXX
%                           size_effect_comparison_summary
%                           contrast_effect_comparison_summary
%
% For condition_specific_models:
%
%   root_dir
%       session_folder
%           catgt_*
%               size_effect_comparison_summary
%               contrast_effect_comparison_summary
%
% Session sorting:
%   The script sorts sessions by the number after "p" in the parent
%   session folder name.
%
% Example:
%   RafiL002p0119_g1 -> S1
%   RafiL001p0120_g1 -> S2
%
% The figure only shows S1, S2, ...
% The saved MultiSessionEffectComparison mat keeps the real folder mapping.
%
% Plot style:
%   'bar_points'
%       bar = mean
%       dots = individual values
%       black square = median
%
%   'violin'
%       violin = distribution
%       dots = individual values
%       black line = median
%       white diamond = mean
%
% Notes:
%   - R2 is read and stored in the output mat but not plotted.
%   - Delta plots use all valid unit-level delta values, not only central
%     points.
%   - Slope plot defaults to regression_central.slope.
%   - Delta plots can use a signed broken-axis display to keep extreme
%     points visible while improving central-region readability.
% =========================================================================

clc;
clear;

%% ========================== USER SETTINGS ==============================

root_dir = 'I:\np_data';

% -------------------------------------------------------------------------
% Effect type
% -------------------------------------------------------------------------
effect_type = 'contrast';
% Options:
% 'size'
% 'contrast'

% -------------------------------------------------------------------------
% Data content
% -------------------------------------------------------------------------
data_content = 'raw_count';
% Options:
% raw_count, raw_fr, z_within_trial, z_within_condition,
% z_across_conditions, demean_count_within_trial,
% demean_fr_within_trial, demean_pooledsd_within_condition

% -------------------------------------------------------------------------
% Model mode
% -------------------------------------------------------------------------
model_mode = 'all_condition_model';
% Options:
% 'all_condition_model'
% 'condition_specific_models'

runIdx = 1;

% -------------------------------------------------------------------------
% Size-only contrast filter
% -------------------------------------------------------------------------
pick_contrast = 0;
% Used only when effect_type = 'size'.
%
% Options:
% 0: all contrasts
% 1: low contrast only
% 2: high contrast only

% -------------------------------------------------------------------------
% Metric name
% -------------------------------------------------------------------------
metric_name = 'CMI';
%
% For effect_type = 'size':
%   'classic_SI'
%   'delta_SL'
%   'S_norm_diff'
%
% For effect_type = 'contrast':
%   'dHL'
%   'CMI'

% -------------------------------------------------------------------------
% Fields to summarize
% -------------------------------------------------------------------------
%
% Original data:
%   y
%
% Base noiseless reconstruction fields after data_reconstruction.m:
%   d
%   yRecon_use_across
%   yRecon_use_within
%   yRecon_use_all
%   yRecon_use_across_no_d
%   yRecon_use_within_no_d
%   yRecon_use_all_no_d
%   yRecon_across_excl_within
%   yRecon_within_excl_across
%
% Feedback / feedforward fields, if generated:
%   yRecon_use_feedback
%   yRecon_feedback_excl_within_ff_ambiguous
%   yRecon_feedback_excl_within
%   yRecon_feedback_excl_ff_ambiguous
%
%   yRecon_use_feedforward
%   yRecon_feedforward_excl_within_fb_ambiguous
%   yRecon_feedforward_excl_within
%   yRecon_feedforward_excl_fb_ambiguous
%
% Reconstruction fields with R noise, if generated:
%   yRecon_use_across_with_R
%   yRecon_use_within_with_R
%   yRecon_use_all_with_R
%   yRecon_across_excl_within_with_R
%   yRecon_within_excl_across_with_R
%
% Reconstruction fields keeping residual, if generated:
%   yRecon_use_across_keep_resid
%   yRecon_use_within_keep_resid
%   yRecon_use_all_keep_resid
%   yRecon_across_excl_within_keep_resid
%   yRecon_within_excl_across_keep_resid

% Baseline fields used on x-axis.
baseline_fields = {'yRecon_use_all'};

% Compared fields used on y-axis.
comparation_fields = { ...
    'yRecon_use_across', ...
    'yRecon_across_excl_within', ...
    'yRecon_use_within', ...
    'yRecon_within_excl_across'};

% -------------------------------------------------------------------------
% Time window selection
% -------------------------------------------------------------------------
time_selection_mode = 'specific_window';
% Options:
% 'full_trial'
% 'specific_window'
%
% For 'full_trial':
%   Select comparison_summary.is_full_trial_single_window == true.
%
% For 'specific_window':
%   Select a small-window result by target_analysis_window,
%   target_sliding_step, and target_time_window_index.

target_analysis_window = 0.2;
target_sliding_step = 0.2;
target_time_window_index = 2;

% -------------------------------------------------------------------------
% Slope summary setting
% -------------------------------------------------------------------------
regression_type_for_slope = 'central';
% Options:
% 'central'
% 'all'
%
% 'central':
%   Use comparison_summary.group(g).regression_central.slope.
%
% 'all':
%   Use comparison_summary.group(g).regression_all.slope.

% -------------------------------------------------------------------------
% Delta broken-axis display
% -------------------------------------------------------------------------
use_broken_axis_for_delta = true;
% true:
%   delta figures use a signed broken-axis display on the y-axis.
%   Extreme positive/negative deltas are still shown, but compressed.
%
% false:
%   delta figures use a normal linear y-axis.

delta_break_start_prctile = 97.0;
% Percentile of abs(delta values) used to start the broken tail.
% Smaller value compresses more points into the tail.
% Larger value keeps more points in the central linear region.

delta_broken_axis_trigger_ratio = 1;
% Broken-axis is used when:
%   raw_abs_max > break_start * delta_broken_axis_trigger_ratio
%
% 1 means use broken-axis whenever extremes exceed break_start.

delta_tail_display_frac = 0.10;
% Fraction of central half-axis used to display each compressed tail.

delta_break_gap_frac = 0.035;
% Visual gap between central region and compressed tail.

delta_min_tail_display_slope = 0.001;
% Minimum display slope in the compressed tail.
% Increase this if extreme tail points look too collapsed.

draw_delta_broken_axis_marks = true;

% -------------------------------------------------------------------------
% Save options
% -------------------------------------------------------------------------
save_mat = true;
save_fig = true;
save_png = true;
close_after_save = true;

% Print full MATLAB error report for skipped sessions.
print_full_error_report = false;

% -------------------------------------------------------------------------
% Plot options
% -------------------------------------------------------------------------
make_plots = true;
fig_visible = 'on';
% 'on' or 'off'

plot_style = 'bar_points';
% Options:
% 'bar_points'
% 'violin'
%
% File names include plot_style so bar and violin figures do not overwrite
% each other.

% Scatter point options.
point_size_slope = 36;
point_size_delta = 10;
point_alpha = 0.70;

% Bar + points mode.
bar_value_mode = 'median';
% options:
% 'mean'
% 'median'
%
% 'mean':
%   bar = mean
%   black square = median
%
% 'median':
%   bar = median
%   black square = mean

bar_alpha = 0.88;
show_summary_marker = true;
point_jitter_width_slope = 0.06;
point_jitter_width_delta = 0.10;

% Violin mode.
violin_alpha = 0.28;
show_mean_marker = true;
show_median_line = true;

% Figure options.
png_dpi = 400;

% Group colors, matched to the rest of your scripts.
group_colors_base = [ ...
    0.0000, 0.4470, 0.7410; ...
    0.8500, 0.3250, 0.0980];

% Session colors in delta plots are generated by making each group color
% progressively darker across S1, S2, ...
session_color_lightness_start = 0.65;
session_color_lightness_end = 0.05;

% Axis options.
draw_zero_line = true;
zero_line_style = 'k--';
zero_line_width = 1.0;

% X-axis layout.
% The script automatically adjusts item spacing and figure width based on
% the number of comparisons, groups, and sessions.
base_fig_height = 720;
slope_fig_width_min = 1000;
delta_fig_width_min = 1200;
max_fig_width = 4200;

%% ======================= VALIDATE SETTINGS =============================

validateUserSettings(effect_type, model_mode, metric_name, ...
    time_selection_mode, regression_type_for_slope, plot_style, ...
    bar_value_mode, pick_contrast);

baseline_fields = normalize_field_list_local(baseline_fields, 'baseline_fields');
comparation_fields = normalize_field_list_local(comparation_fields, 'comparation_fields');

effect_tag = makeEffectTag(effect_type);
model_tag = makeModelTag(model_mode);
metric_tag = makeMetricTag(effect_type, metric_name);
contrast_filter = buildContrastFilter(pick_contrast);

time_tag = makeTimeTag(time_selection_mode, ...
    target_analysis_window, target_sliding_step, target_time_window_index);

comparison_file_tag = makeComparisonSetFileTag(baseline_fields, comparation_fields);
delta_axis_file_tag = makeDeltaAxisFileTag(use_broken_axis_for_delta);

if strcmp(effect_type, 'size')
    out_base = sprintf('%s_%s_effectComp_%s_%s_%s_%s_%s', ...
        data_content, effect_tag, model_tag, metric_tag, ...
        comparison_file_tag, contrast_filter.file_tag, time_tag);
else
    out_base = sprintf('%s_%s_effectComp_%s_%s_%s_%s', ...
        data_content, effect_tag, model_tag, metric_tag, ...
        comparison_file_tag, time_tag);
end

summary_folder_name = getSummaryFolderName(effect_type);

fprintf('Root dir              : %s\n', root_dir);
fprintf('Effect type           : %s\n', effect_type);
fprintf('Data content          : %s\n', data_content);
fprintf('Model mode            : %s\n', model_mode);
fprintf('Run index             : %d\n', runIdx);
fprintf('Metric                : %s\n', metric_name);
fprintf('Comparison file tag   : %s\n', comparison_file_tag);

if strcmp(effect_type, 'size')
    fprintf('Pick contrast         : %d (%s)\n', ...
        pick_contrast, contrast_filter.label);
end

fprintf('Time selection        : %s\n', time_selection_mode);

if strcmp(time_selection_mode, 'specific_window')
    fprintf('Target window         : analysis_window %.12g, step %.12g, window %d\n', ...
        target_analysis_window, target_sliding_step, target_time_window_index);
end

fprintf('Regression for slope  : %s\n', regression_type_for_slope);
fprintf('Plot style            : %s\n', plot_style);
fprintf('Delta axis            : %s\n', delta_axis_file_tag);
fprintf('Summary folder        : %s\n', summary_folder_name);
fprintf('Output base           : %s\n', out_base);

%% ======================= FIND SESSION FOLDERS ==========================

session_dirs = findCatgtSessionDirs(root_dir);

if isempty(session_dirs)
    error('No catgt_* folders found under one level below root_dir: %s', root_dir);
end

fprintf('\nFound %d candidate catgt_* session folders.\n', numel(session_dirs));

%% ======================= READ ALL SESSIONS =============================

records = {};
skipped = struct('session_dir', {}, 'reason', {});
ref = struct();

for si = 1:numel(session_dirs)
    session_dir = session_dirs{si};

    fprintf('\n[%d/%d] Reading %s\n', si, numel(session_dirs), session_dir);

    try
        [rec, ref] = readOneSessionEffectComparison( ...
            session_dir, ...
            effect_type, data_content, model_mode, runIdx, ...
            pick_contrast, contrast_filter, ...
            metric_name, ...
            baseline_fields, comparation_fields, ...
            time_selection_mode, ...
            target_analysis_window, target_sliding_step, ...
            target_time_window_index, ...
            summary_folder_name, ...
            ref);

        records{end+1} = rec; %#ok<SAGROW>

    catch ME
        skipped(end+1).session_dir = session_dir; %#ok<SAGROW>
        skipped(end).reason = ME.message;

        warning('Skipping session: %s\nReason: %s', session_dir, ME.message);

        if print_full_error_report
            fprintf('\nFull error report for skipped session:\n');
            fprintf('%s\n', getReport(ME, 'extended', 'hyperlinks', 'off'));
        end
    end
end

if isempty(records)
    fprintf('\nSkipped sessions:\n');
    for k = 1:numel(skipped)
        fprintf('  %s\n    %s\n', skipped(k).session_dir, skipped(k).reason);
    end

    error('No valid sessions were loaded.');
end

fprintf('\nLoaded %d valid sessions.\n', numel(records));
fprintf('Skipped %d sessions.\n', numel(skipped));

%% ======================= STACK VALUES ==================================

MultiSessionEffectComparison = buildMultiSessionEffectComparison( ...
    records, skipped, ref, root_dir, ...
    effect_type, data_content, model_mode, runIdx, ...
    pick_contrast, contrast_filter, metric_name, ...
    baseline_fields, comparation_fields, ...
    time_selection_mode, target_analysis_window, ...
    target_sliding_step, target_time_window_index, ...
    regression_type_for_slope, ...
    use_broken_axis_for_delta, ...
    delta_break_start_prctile, ...
    delta_broken_axis_trigger_ratio, ...
    delta_tail_display_frac, ...
    delta_break_gap_frac, ...
    delta_min_tail_display_slope, ...
    out_base);

if save_mat
    mat_file = fullfile(root_dir, [out_base '.mat']);
    save(mat_file, 'MultiSessionEffectComparison', '-v7.3');
    fprintf('\nSaved mat:\n  %s\n', mat_file);
end

%% ======================= PLOT ==========================================

if make_plots
    fig_handles = plotMultiSessionEffectComparison( ...
        MultiSessionEffectComparison, fig_visible, plot_style, ...
        group_colors_base, ...
        session_color_lightness_start, session_color_lightness_end, ...
        point_size_slope, point_size_delta, point_alpha, ...
        bar_alpha, bar_value_mode, show_summary_marker, ...
        point_jitter_width_slope, point_jitter_width_delta, ...
        violin_alpha, show_mean_marker, show_median_line, ...
        draw_zero_line, zero_line_style, zero_line_width, ...
        use_broken_axis_for_delta, ...
        delta_break_start_prctile, ...
        delta_broken_axis_trigger_ratio, ...
        delta_tail_display_frac, ...
        delta_break_gap_frac, ...
        delta_min_tail_display_slope, ...
        draw_delta_broken_axis_marks, ...
        slope_fig_width_min, delta_fig_width_min, ...
        base_fig_height, max_fig_width);

    if save_fig || save_png
        figure_tags = { ...
            'slope', ...
            ['delta_base_ge0_', delta_axis_file_tag], ...
            ['delta_base_lt0_', delta_axis_file_tag]};

        for f = 1:numel(fig_handles)
            if ~ishandle(fig_handles(f))
                continue;
            end

            plot_style_file_tag = makePlotStyleFileTag(plot_style, bar_value_mode);
            fig_base = sprintf('%s_%s_%s', out_base, plot_style_file_tag, figure_tags{f});

            if save_fig
                fig_file = fullfile(root_dir, [fig_base '.fig']);
                savefig(fig_handles(f), fig_file);
                fprintf('Saved FIG:\n  %s\n', fig_file);
            end

            if save_png
                png_file = fullfile(root_dir, [fig_base '.png']);
                savePngLocal(fig_handles(f), png_file, png_dpi);
                fprintf('Saved PNG:\n  %s\n', png_file);
            end
        end
    end

    if close_after_save
        close(fig_handles(ishandle(fig_handles)));
    end
end

fprintf('\nDone.\n');

%% ========================================================================
% Local functions
% ========================================================================

function validateUserSettings(effect_type, model_mode, metric_name, ...
    time_selection_mode, regression_type_for_slope, plot_style, ...
    bar_value_mode, pick_contrast)

valid_bar_value_mode = {'mean', 'median'};
assertStringOption(bar_value_mode, valid_bar_value_mode, 'bar_value_mode');

valid_effect = {'size', 'contrast'};
valid_model = {'all_condition_model', 'condition_specific_models'};
valid_time = {'full_trial', 'specific_window'};
valid_regression = {'central', 'all'};
valid_plot_style = {'bar_points', 'violin'};

assertStringOption(effect_type, valid_effect, 'effect_type');
assertStringOption(model_mode, valid_model, 'model_mode');
assertStringOption(time_selection_mode, valid_time, 'time_selection_mode');
assertStringOption(regression_type_for_slope, valid_regression, 'regression_type_for_slope');
assertStringOption(plot_style, valid_plot_style, 'plot_style');

switch char(effect_type)
    case 'size'
        valid_metric = {'classic_SI', 'delta_SL', 'S_norm_diff'};
        assertStringOption(metric_name, valid_metric, 'metric_name');

        if ~(isnumeric(pick_contrast) || islogical(pick_contrast)) || ...
                ~isscalar(pick_contrast) || ...
                ~ismember(double(pick_contrast), [0 1 2])
            error('For effect_type = size, pick_contrast must be 0, 1, or 2.');
        end

    case 'contrast'
        valid_metric = {'dHL', 'CMI'};
        assertStringOption(metric_name, valid_metric, 'metric_name');

    otherwise
        error('Unknown effect_type: %s', effect_type);
end
end

function assertStringOption(value, validOptions, varName)
if ~ischar(value) && ~isstring(value)
    error('%s must be a char or string.', varName);
end

value = char(value);

if ~any(strcmp(value, validOptions))
    error('%s = ''%s'' is invalid. Valid options are: %s', ...
        varName, value, strjoin(validOptions, ', '));
end
end

function fields = normalize_field_list_local(fields, var_name)
if ischar(fields)
    fields = {fields};
elseif isstring(fields)
    fields = cellstr(fields(:))';
elseif iscell(fields)
    fields = reshape(fields, 1, []);

    for i = 1:numel(fields)
        if isstring(fields{i})
            fields{i} = char(fields{i});
        end

        if ~ischar(fields{i})
            error('%s{%d} must be a char or string.', var_name, i);
        end
    end
else
    error('%s must be a char, string, string array, or cell array.', var_name);
end

if isempty(fields)
    error('%s is empty.', var_name);
end

empty_mask = cellfun(@isempty, fields);

if any(empty_mask)
    error('%s contains empty entries.', var_name);
end
end

function tag = makeEffectTag(effect_type)
switch char(effect_type)
    case 'size'
        tag = 'size';

    case 'contrast'
        tag = 'contrast';

    otherwise
        error('Unknown effect_type: %s', effect_type);
end
end

function tag = makeModelTag(model_mode)
switch char(model_mode)
    case 'condition_specific_models'
        tag = 'condition_specific_M';

    case 'all_condition_model'
        tag = 'all_condition_M';

    otherwise
        error('Unknown model_mode: %s', model_mode);
end
end

function tag = makeMetricTag(effect_type, metric_name)
switch char(effect_type)
    case 'size'
        switch char(metric_name)
            case 'classic_SI'
                tag = 'SI';

            case 'delta_SL'
                tag = 'dSL';

            case 'S_norm_diff'
                tag = 'SnD';

            otherwise
                error('Unknown size metric_name: %s', metric_name);
        end

    case 'contrast'
        switch char(metric_name)
            case 'dHL'
                tag = 'dHL';

            case 'CMI'
                tag = 'CMI';

            otherwise
                error('Unknown contrast metric_name: %s', metric_name);
        end

    otherwise
        error('Unknown effect_type: %s', effect_type);
end
end

function contrast_filter = buildContrastFilter(pick_contrast)
pick_contrast = double(pick_contrast);

contrast_filter = struct();
contrast_filter.pick_contrast = pick_contrast;

switch pick_contrast
    case 0
        contrast_filter.label = 'all_contrasts';
        contrast_filter.file_suffix = '';
        contrast_filter.file_tag = 'allContrast';

    case 1
        contrast_filter.label = 'low_contrast';
        contrast_filter.file_suffix = '_low_contrast';
        contrast_filter.file_tag = 'lowContrast';

    case 2
        contrast_filter.label = 'high_contrast';
        contrast_filter.file_suffix = '_high_contrast';
        contrast_filter.file_tag = 'highContrast';

    otherwise
        error('pick_contrast must be 0, 1, or 2.');
end
end

function tag = makeTimeTag(time_selection_mode, analysis_window, sliding_step, window_index)
switch char(time_selection_mode)
    case 'full_trial'
        tag = 'fullTrial';

    case 'specific_window'
        tag = sprintf('wn%s_st%s_w%02d', ...
            formatSecondsForFileTag(analysis_window), ...
            formatSecondsForFileTag(sliding_step), ...
            window_index);

    otherwise
        error('Unknown time_selection_mode: %s', time_selection_mode);
end
end

function s = formatSecondsForFileTag(x)
s = sprintf('%.12g', x);
s = strrep(s, '.', '_');
s = strrep(s, '-', 'm');
s = regexprep(s, '[^a-zA-Z0-9_]', '_');
s = regexprep(s, '_+', '_');
end

function tag = makeComparisonSetFileTag(baseline_fields, comparation_fields)
nBase = numel(baseline_fields);
nComp = numel(comparation_fields);
parts = cell(1, nBase * nComp);
idx = 0;

for b = 1:nBase
    for c = 1:nComp
        idx = idx + 1;
        base_tag = analysisFieldToFileTagLocal(baseline_fields{b});
        comp_tag = analysisFieldToFileTagLocal(comparation_fields{c});
        parts{idx} = sprintf('%s_vs_%s', comp_tag, base_tag);
    end
end

tag = strjoin(parts, '__');
tag = makeSafeFileTagLocal(tag);
end

function tag = analysisFieldToFileTagLocal(field_name)
switch char(field_name)
    case 'y'
        tag = 'y';

    case 'd'
        tag = 'd';

    case 'yRecon_use_all'
        tag = 'all';

    case 'yRecon_use_all_no_d'
        tag = 'all_no_d';

    case 'yRecon_use_across'
        tag = 'acr';

    case 'yRecon_use_across_no_d'
        tag = 'acr_no_d';

    case 'yRecon_use_within'
        tag = 'win';

    case 'yRecon_use_within_no_d'
        tag = 'win_no_d';

    case 'yRecon_across_excl_within'
        tag = 'acr_excl_win';

    case 'yRecon_within_excl_across'
        tag = 'win_excl_acr';

    case 'yRecon_use_feedback'
        tag = 'fb';

    case 'yRecon_feedback_excl_within_ff_ambiguous'
        tag = 'fb_excl_win_ff_amb';

    case 'yRecon_feedback_excl_within'
        tag = 'fb_excl_win';

    case 'yRecon_feedback_excl_ff_ambiguous'
        tag = 'fb_excl_ff_amb';

    case 'yRecon_use_feedforward'
        tag = 'ff';

    case 'yRecon_feedforward_excl_within_fb_ambiguous'
        tag = 'ff_excl_win_fb_amb';

    case 'yRecon_feedforward_excl_within'
        tag = 'ff_excl_win';

    case 'yRecon_feedforward_excl_fb_ambiguous'
        tag = 'ff_excl_fb_amb';

    case 'yRecon_use_all_with_R'
        tag = 'all_R';

    case 'yRecon_use_across_with_R'
        tag = 'acr_R';

    case 'yRecon_use_within_with_R'
        tag = 'win_R';

    case 'yRecon_across_excl_within_with_R'
        tag = 'acr_excl_win_R';

    case 'yRecon_within_excl_across_with_R'
        tag = 'win_excl_acr_R';

    case 'yRecon_use_all_keep_resid'
        tag = 'all_KR';

    case 'yRecon_use_across_keep_resid'
        tag = 'acr_KR';

    case 'yRecon_use_within_keep_resid'
        tag = 'win_KR';

    case 'yRecon_across_excl_within_keep_resid'
        tag = 'acr_excl_win_KR';

    case 'yRecon_within_excl_across_keep_resid'
        tag = 'win_excl_acr_KR';

    otherwise
        tag = fallbackShortFieldLabel(field_name);
        tag = makeSafeFileTagLocal(tag);
end
end

function tag = makePlotStyleFileTag(plot_style, bar_value_mode)
switch char(plot_style)
    case 'bar_points'
        tag = sprintf('bar_points_barAs%s', char(bar_value_mode));

    case 'violin'
        tag = 'violin';

    otherwise
        tag = makeSafeFileTagLocal(plot_style);
end
end

function tag = makeSafeFileTagLocal(x)
tag = char(x);
tag = strtrim(tag);
tag = strrep(tag, ' ', '_');
tag = strrep(tag, '-', '_');
tag = strrep(tag, '/', '_');
tag = strrep(tag, '\', '_');
tag = regexprep(tag, '[^a-zA-Z0-9_]', '_');
tag = regexprep(tag, '_+', '_');
tag = regexprep(tag, '^_+', '');
tag = regexprep(tag, '_+$', '');

if isempty(tag)
    tag = 'untitled';
end
end

function tag = makeDeltaAxisFileTag(use_broken_axis_for_delta)
if use_broken_axis_for_delta
    tag = 'deltaBroken';
else
    tag = 'deltaLinear';
end
end

function folder_name = getSummaryFolderName(effect_type)
switch char(effect_type)
    case 'size'
        folder_name = 'size_effect_comparison_summary';

    case 'contrast'
        folder_name = 'contrast_effect_comparison_summary';

    otherwise
        error('Unknown effect_type: %s', effect_type);
end
end

function session_dirs = findCatgtSessionDirs(root_dir)
listing = dir(fullfile(root_dir, '*', 'catgt_*'));
listing = listing([listing.isdir]);

if isempty(listing)
    session_dirs = {};
    return;
end

session_dirs = cell(1, numel(listing));
sort_keys = nan(1, numel(listing));
name_keys = cell(1, numel(listing));

for k = 1:numel(listing)
    session_dirs{k} = fullfile(listing(k).folder, listing(k).name);

    [parent_dir, ~] = fileparts(session_dirs{k});
    [~, parent_name] = fileparts(parent_dir);

    sort_keys(k) = extractSessionNumberFromName(parent_name);
    name_keys{k} = parent_name;
end

T = table(sort_keys(:), name_keys(:), session_dirs(:), ...
    'VariableNames', {'session_number', 'session_name', 'session_dir'});

T = sortrows(T, {'session_number', 'session_name'});
session_dirs = T.session_dir(:)';
end

function session_number = extractSessionNumberFromName(session_name)
tokens = regexp(session_name, 'p(\d+)', 'tokens', 'once');

if isempty(tokens)
    session_number = inf;
else
    session_number = str2double(tokens{1});

    if ~isfinite(session_number)
        session_number = inf;
    end
end
end

function [rec, ref] = readOneSessionEffectComparison( ...
    session_dir, ...
    effect_type, data_content, model_mode, runIdx, ...
    pick_contrast, contrast_filter, metric_name, ...
    baseline_fields, comparation_fields, ...
    time_selection_mode, ...
    target_analysis_window, target_sliding_step, target_time_window_index, ...
    summary_folder_name, ref)

summary_dir = getSummaryDirForSession(session_dir, data_content, model_mode, ...
    runIdx, summary_folder_name);

if ~exist(summary_dir, 'dir')
    error('Summary folder not found: %s', summary_dir);
end

summary_files = dir(fullfile(summary_dir, '*.mat'));

if isempty(summary_files)
    error('No summary mat files found in: %s', summary_dir);
end

comparison_list = buildComparisonList(baseline_fields, comparation_fields);
loaded_summaries = loadAllComparisonSummaries(summary_dir, summary_files);

rec = struct();
rec.session_dir = session_dir;
rec.session_name = getSessionName(session_dir);
rec.session_parent_name = getSessionParentName(session_dir);
rec.session_number = extractSessionNumberFromName(rec.session_parent_name);
rec.summary_dir = summary_dir;
rec.comparison = repmat(struct(), 1, numel(comparison_list));

for c = 1:numel(comparison_list)
    target_base = comparison_list(c).baseline_field;
    target_comp = comparison_list(c).comparation_field;

    [summary, summary_file] = findMatchingComparisonSummary( ...
        loaded_summaries, ...
        effect_type, data_content, model_mode, runIdx, ...
        pick_contrast, contrast_filter, metric_name, ...
        target_base, target_comp, ...
        time_selection_mode, ...
        target_analysis_window, target_sliding_step, target_time_window_index);

    validateComparisonSummaryForUse(summary, effect_type, metric_name, ...
        target_base, target_comp, summary_file);

    rec.comparison(c).comparison_index = c;
    rec.comparison(c).baseline_field = target_base;
    rec.comparison(c).comparation_field = target_comp;
    rec.comparison(c).comparison_label = makeComparisonLabel(target_base, target_comp);
    rec.comparison(c).summary_file = summary_file;
    rec.comparison(c).summary = summary;
end

ref = updateAndCheckEffectReference(ref, rec, comparison_list, session_dir);
end

function summary_dir = getSummaryDirForSession(session_dir, data_content, model_mode, ...
    runIdx, summary_folder_name)

switch char(model_mode)
    case 'all_condition_model'
        summary_dir = fullfile(session_dir, sprintf('FA_Dlag_%s', data_content), ...
            'mat_results', sprintf('run%03d', runIdx), summary_folder_name);

    case 'condition_specific_models'
        summary_dir = fullfile(session_dir, summary_folder_name);

    otherwise
        error('Unknown model_mode: %s', model_mode);
end
end

function comparison_list = buildComparisonList(baseline_fields, comparation_fields)
nBase = numel(baseline_fields);
nComp = numel(comparation_fields);

comparison_list = repmat(struct( ...
    'comparison_index', [], ...
    'baseline_field', '', ...
    'comparation_field', '', ...
    'comparison_label', ''), 1, nBase * nComp);

idx = 0;

for b = 1:nBase
    for c = 1:nComp
        idx = idx + 1;

        comparison_list(idx).comparison_index = idx;
        comparison_list(idx).baseline_field = baseline_fields{b};
        comparison_list(idx).comparation_field = comparation_fields{c};
        comparison_list(idx).comparison_label = makeComparisonLabel( ...
            baseline_fields{b}, comparation_fields{c});
    end
end
end

function loaded = loadAllComparisonSummaries(summary_dir, summary_files)
loaded = repmat(struct( ...
    'file', '', ...
    'comparison_summary', []), 1, numel(summary_files));

for i = 1:numel(summary_files)
    this_file = fullfile(summary_dir, summary_files(i).name);
    S = load(this_file);

    if ~isfield(S, 'comparison_summary')
        loaded(i).file = this_file;
        loaded(i).comparison_summary = [];
        continue;
    end

    loaded(i).file = this_file;
    loaded(i).comparison_summary = S.comparison_summary;
end
end

function [summary, summary_file] = findMatchingComparisonSummary( ...
    loaded_summaries, ...
    effect_type, data_content, model_mode, runIdx, ...
    pick_contrast, contrast_filter, metric_name, ...
    baseline_field, comparation_field, ...
    time_selection_mode, ...
    target_analysis_window, target_sliding_step, target_time_window_index)

match_idx = false(1, numel(loaded_summaries));

for i = 1:numel(loaded_summaries)
    S = loaded_summaries(i).comparison_summary;

    if isempty(S)
        continue;
    end

    if summaryMatchesTarget(S, effect_type, data_content, model_mode, runIdx, ...
            pick_contrast, contrast_filter, metric_name, ...
            baseline_field, comparation_field, ...
            time_selection_mode, ...
            target_analysis_window, target_sliding_step, target_time_window_index)
        match_idx(i) = true;
    end
end

idx = find(match_idx);

if isempty(idx)
    error(['No matching comparison_summary found for:\n', ...
        '  metric: %s\n', ...
        '  baseline: %s\n', ...
        '  compared: %s'], ...
        metric_name, baseline_field, comparation_field);
end

if numel(idx) > 1
    fprintf('\nMatched files:\n');
    for k = 1:numel(idx)
        fprintf('  %s\n', loaded_summaries(idx(k)).file);
    end

    error(['More than one matching comparison_summary found for ', ...
        '%s vs %s. Make the time/metric/contrast selection more specific.'], ...
        comparation_field, baseline_field);
end

summary = loaded_summaries(idx).comparison_summary;
summary_file = loaded_summaries(idx).file;
end

function tf = summaryMatchesTarget(S, effect_type, data_content, model_mode, runIdx, ...
    pick_contrast, contrast_filter, metric_name, ...
    baseline_field, comparation_field, ...
    time_selection_mode, ...
    target_analysis_window, target_sliding_step, target_time_window_index)

tf = true;

tf = tf && isfield(S, 'effect_type') && strcmp(char(S.effect_type), char(effect_type));
tf = tf && isfield(S, 'data_content') && strcmp(char(S.data_content), char(data_content));
tf = tf && isfield(S, 'model_mode') && strcmp(char(S.model_mode), char(model_mode));
tf = tf && isfield(S, 'metric_name') && strcmp(char(S.metric_name), char(metric_name));
tf = tf && isfield(S, 'baseline_field') && strcmp(char(S.baseline_field), char(baseline_field));
tf = tf && isfield(S, 'comparation_field') && strcmp(char(S.comparation_field), char(comparation_field));

if isfield(S, 'runIdx')
    tf = tf && isequal(double(S.runIdx), double(runIdx));
end

if strcmp(effect_type, 'size')
    tf = tf && isfield(S, 'pick_contrast') && ...
        isequal(double(S.pick_contrast), double(pick_contrast));

    if isfield(S, 'contrast_label')
        tf = tf && strcmp(char(S.contrast_label), contrast_filter.label);
    end
end

tf = tf && timeInfoMatchesTarget(S, time_selection_mode, ...
    target_analysis_window, target_sliding_step, target_time_window_index);
end

function tf = timeInfoMatchesTarget(S, time_selection_mode, ...
    target_analysis_window, target_sliding_step, target_time_window_index)

required_fields = { ...
    'is_full_trial_single_window', ...
    'analysis_window', ...
    'sliding_step', ...
    'time_window_index'};

for i = 1:numel(required_fields)
    if ~isfield(S, required_fields{i})
        tf = false;
        return;
    end
end

tol = 1e-10;

switch char(time_selection_mode)
    case 'full_trial'
        tf = logical(S.is_full_trial_single_window);

    case 'specific_window'
        tf = ~logical(S.is_full_trial_single_window) && ...
            abs(double(S.analysis_window) - target_analysis_window) <= tol && ...
            abs(double(S.sliding_step) - target_sliding_step) <= tol && ...
            double(S.time_window_index) == double(target_time_window_index);

    otherwise
        error('Unknown time_selection_mode: %s', time_selection_mode);
end
end

function validateComparisonSummaryForUse(S, effect_type, metric_name, ...
    baseline_field, comparation_field, summary_file)

required_fields = { ...
    'effect_type', ...
    'metric_name', ...
    'baseline_field', ...
    'comparation_field', ...
    'group', ...
    'groupd', ...
    'group_names', ...
    'analysis_window', ...
    'sliding_step', ...
    'time_window_index', ...
    'is_full_trial_single_window'};

for i = 1:numel(required_fields)
    if ~isfield(S, required_fields{i})
        error('comparison_summary in %s is missing field %s.', ...
            summary_file, required_fields{i});
    end
end

if ~strcmp(char(S.effect_type), char(effect_type))
    error('Effect type mismatch in %s.', summary_file);
end

if ~strcmp(char(S.metric_name), char(metric_name))
    error('Metric name mismatch in %s.', summary_file);
end

if ~strcmp(char(S.baseline_field), char(baseline_field)) || ...
        ~strcmp(char(S.comparation_field), char(comparation_field))
    error('Field comparison mismatch in %s.', summary_file);
end

for g = 1:numel(S.group)
    if ~isfield(S.group(g), 'regression_all')
        error('summary.group(%d).regression_all missing in %s.', g, summary_file);
    end

    if ~isfield(S.group(g), 'regression_central')
        error('summary.group(%d).regression_central missing in %s.', g, summary_file);
    end

    if ~isfield(S.group(g), 'delta_by_base_sign') || ...
            ~isfield(S.group(g).delta_by_base_sign, 'positive_base') || ...
            ~isfield(S.group(g).delta_by_base_sign, 'negative_base')
        error('summary.group(%d).delta_by_base_sign missing in %s.', g, summary_file);
    end
end
end

function ref = updateAndCheckEffectReference(ref, rec, comparison_list, session_dir)
first_summary = rec.comparison(1).summary;

nGroups = numel(first_summary.group);
group_names = first_summary.group_names;

if isstring(group_names)
    group_names = cellstr(group_names);
end

group_names = reshape(group_names, 1, []);

if isempty(fieldnames(ref))
    ref.nGroups = nGroups;
    ref.group_names = group_names;
    ref.comparison_list = comparison_list;
    return;
end

if ref.nGroups ~= nGroups
    error('Number of groups mismatch in %s. Got %d, expected %d.', ...
        session_dir, nGroups, ref.nGroups);
end

% Important:
% Different sessions can have different numbers of units in each group.
% This is expected. Only the number of groups must match across sessions.

if numel(ref.comparison_list) ~= numel(comparison_list)
    error('Number of comparisons mismatch in %s.', session_dir);
end

for c = 1:numel(comparison_list)
    if ~strcmp(ref.comparison_list(c).baseline_field, comparison_list(c).baseline_field) || ...
            ~strcmp(ref.comparison_list(c).comparation_field, comparison_list(c).comparation_field)
        error('Comparison list mismatch in %s.', session_dir);
    end
end
end

function name = getSessionName(session_dir)
[parent_dir, catgt_name] = fileparts(session_dir);
[~, parent_name] = fileparts(parent_dir);
name = sprintf('%s/%s', parent_name, catgt_name);
end

function parent_name = getSessionParentName(session_dir)
[parent_dir, ~] = fileparts(session_dir);
[~, parent_name] = fileparts(parent_dir);
end

function M = buildMultiSessionEffectComparison( ...
    records, skipped, ref, root_dir, ...
    effect_type, data_content, model_mode, runIdx, ...
    pick_contrast, contrast_filter, metric_name, ...
    baseline_fields, comparation_fields, ...
    time_selection_mode, target_analysis_window, ...
    target_sliding_step, target_time_window_index, ...
    regression_type_for_slope, ...
    use_broken_axis_for_delta, ...
    delta_break_start_prctile, ...
    delta_broken_axis_trigger_ratio, ...
    delta_tail_display_frac, ...
    delta_break_gap_frac, ...
    delta_min_tail_display_slope, ...
    out_base)

nSessions = numel(records);
nComparisons = numel(ref.comparison_list);
nGroups = ref.nGroups;

session_info = struct( ...
    'session_index', {}, ...
    'session_label', {}, ...
    'session_name', {}, ...
    'session_parent_name', {}, ...
    'session_number', {}, ...
    'session_dir', {}, ...
    'summary_dir', {}, ...
    'groupd', {});

for s = 1:nSessions
    session_info(s).session_index = s;
    session_info(s).session_label = sprintf('S%d', s);
    session_info(s).session_name = records{s}.session_name;
    session_info(s).session_parent_name = records{s}.session_parent_name;
    session_info(s).session_number = records{s}.session_number;
    session_info(s).session_dir = records{s}.session_dir;
    session_info(s).summary_dir = records{s}.summary_dir;
    session_info(s).groupd = records{s}.comparison(1).summary.groupd;
end

comparison_info = struct( ...
    'comparison_index', {}, ...
    'baseline_field', {}, ...
    'comparation_field', {}, ...
    'comparison_label', {});

for c = 1:nComparisons
    comparison_info(c).comparison_index = c;
    comparison_info(c).baseline_field = ref.comparison_list(c).baseline_field;
    comparison_info(c).comparation_field = ref.comparison_list(c).comparation_field;
    comparison_info(c).comparison_label = makeComparisonLabel( ...
        ref.comparison_list(c).baseline_field, ...
        ref.comparison_list(c).comparation_field);
end

slope_all = nan(nSessions, nComparisons, nGroups);
slope_central = nan(nSessions, nComparisons, nGroups);
R2_all = nan(nSessions, nComparisons, nGroups);
R2_central = nan(nSessions, nComparisons, nGroups);

delta_positive = cell(nSessions, nComparisons, nGroups);
delta_negative = cell(nSessions, nComparisons, nGroups);

summary_file = cell(nSessions, nComparisons);

for s = 1:nSessions
    for c = 1:nComparisons
        S = records{s}.comparison(c).summary;
        summary_file{s, c} = records{s}.comparison(c).summary_file;

        for g = 1:nGroups
            reg_all = S.group(g).regression_all;
            reg_central = S.group(g).regression_central;

            slope_all(s, c, g) = getRegressionFieldValue(reg_all, 'slope');
            slope_central(s, c, g) = getRegressionFieldValue(reg_central, 'slope');

            R2_all(s, c, g) = getRegressionFieldValue(reg_all, 'R2');
            R2_central(s, c, g) = getRegressionFieldValue(reg_central, 'R2');

            delta_positive{s, c, g} = getDeltaValuesFromSplit( ...
                S.group(g).delta_by_base_sign.positive_base);

            delta_negative{s, c, g} = getDeltaValuesFromSplit( ...
                S.group(g).delta_by_base_sign.negative_base);
        end
    end
end

switch char(regression_type_for_slope)
    case 'central'
        slope_for_plot = slope_central;
        R2_for_slope = R2_central;

    case 'all'
        slope_for_plot = slope_all;
        R2_for_slope = R2_all;

    otherwise
        error('Unknown regression_type_for_slope: %s', regression_type_for_slope);
end

M = struct();

M.meta.root_dir = root_dir;
M.meta.effect_type = effect_type;
M.meta.data_content = data_content;
M.meta.model_mode = model_mode;
M.meta.runIdx = runIdx;
M.meta.pick_contrast = pick_contrast;
M.meta.contrast_label = contrast_filter.label;
M.meta.metric_name = metric_name;
M.meta.time_selection_mode = time_selection_mode;
M.meta.target_analysis_window = target_analysis_window;
M.meta.target_sliding_step = target_sliding_step;
M.meta.target_time_window_index = target_time_window_index;
M.meta.regression_type_for_slope = regression_type_for_slope;
M.meta.use_broken_axis_for_delta = use_broken_axis_for_delta;
M.meta.delta_break_start_prctile = delta_break_start_prctile;
M.meta.delta_broken_axis_trigger_ratio = delta_broken_axis_trigger_ratio;
M.meta.delta_tail_display_frac = delta_tail_display_frac;
M.meta.delta_break_gap_frac = delta_break_gap_frac;
M.meta.delta_min_tail_display_slope = delta_min_tail_display_slope;
M.meta.output_base = out_base;
M.meta.comparison_file_tag = makeComparisonSetFileTag(baseline_fields, comparation_fields);
M.meta.num_sessions = nSessions;
M.meta.num_comparisons = nComparisons;
M.meta.num_groups = nGroups;

M.settings.baseline_fields = baseline_fields;
M.settings.comparation_fields = comparation_fields;

M.labels.group_names = ref.group_names;
M.labels.group_short = makeGroupShortLabels(nGroups);
M.labels.comparison = {comparison_info.comparison_label};
M.labels.session = {session_info.session_label};

M.sessions.included = session_info;
M.sessions.skipped = skipped;

M.comparisons = comparison_info;
M.summary_file = summary_file;

M.values.slope_all = slope_all;
M.values.slope_central = slope_central;
M.values.slope_for_plot = slope_for_plot;

M.values.R2_all = R2_all;
M.values.R2_central = R2_central;
M.values.R2_for_slope = R2_for_slope;

M.values.delta_positive_base = delta_positive;
M.values.delta_negative_base = delta_negative;

M.dimension_names.slope = {'session', 'comparison', 'group'};
M.dimension_names.delta = {'session', 'comparison', 'group'};

M.notes.delta_definition = 'delta = compared metric - baseline metric';
M.notes.delta_positive_base = 'baseline metric >= 0';
M.notes.delta_negative_base = 'baseline metric < 0';
M.notes.slope_default = ...
    'slope_for_plot uses regression_type_for_slope, default central';
M.notes.groupd = ...
    'groupd can differ across sessions; each session groupd is saved in sessions.included(s).groupd';
end

function v = getRegressionFieldValue(reg, field_name)
if isfield(reg, field_name)
    v = reg.(field_name);
else
    v = NaN;
end

if isempty(v) || ~isscalar(v) || ~isnumeric(v)
    v = NaN;
end
end

function vals = getDeltaValuesFromSplit(split_summary)
if isfield(split_summary, 'delta_values')
    vals = split_summary.delta_values(:);
else
    vals = [];
end

vals = vals(isfinite(vals));
end

function labels = makeGroupShortLabels(nGroups)
labels = cell(1, nGroups);

for g = 1:nGroups
    labels{g} = sprintf('G%d', g);
end
end

