    M, fig_visible, plot_style, group_colors_base, ...
    point_size, point_alpha, ...
    bar_alpha, bar_value_mode, show_summary_marker, point_jitter_width, ...
    violin_alpha, show_mean_marker, show_median_line, ...
    draw_zero_line, zero_line_style, zero_line_width, ...
    fig_width_min, fig_height, max_fig_width)

values = M.values.slope_for_plot;

nComparisons = size(values, 2);
nGroups = size(values, 3);

layout = computeSlopeLayout(nComparisons, nGroups);

fig_width = min(max_fig_width, max(fig_width_min, 260 * nComparisons + 220));

hfig = figure('Visible', fig_visible, ...
    'Color', 'w', ...
    'Position', [100 100 fig_width fig_height], ...
    'Name', 'Session slope summary');

ax = axes(hfig);
hold(ax, 'on');

set(ax, 'Units', 'normalized');
set(ax, 'Position', [0.07 0.20 0.80 0.70]);

group_colors = resolveGroupColors(group_colors_base, nGroups);

bar_width = computeAdaptiveItemWidth(nComparisons * nGroups, 0.25, 0.55);
violin_width = computeAdaptiveItemWidth(nComparisons * nGroups, 0.18, 0.42);

axis_info_linear = makeLinearAxisInfo();

for c = 1:nComparisons
    for g = 1:nGroups
        x0 = layout.group_x(c, g);
        y = squeeze(values(:, c, g));
        color = group_colors(g, :);

        switch char(plot_style)
            case 'bar_points'
                drawBarWithPoints(ax, x0, y, bar_width, color, ...
                    point_size, point_alpha, bar_alpha, ...
                    point_jitter_width, bar_value_mode, show_summary_marker, axis_info_linear);

            case 'violin'
                drawViolinWithPoints(ax, x0, y, violin_width, color, ...
                    point_size, point_alpha, violin_alpha, ...
                    show_mean_marker, show_median_line, axis_info_linear);

            otherwise
                error('Unknown plot_style: %s', plot_style);
        end
    end
end

if draw_zero_line
    yline(ax, 0, zero_line_style, ...
        'LineWidth', zero_line_width, ...
        'HandleVisibility', 'off');
end

applySlopeAxisFormatting(ax, M, layout, values);

dummy = gobjects(1, nGroups);
for g = 1:nGroups
    dummy(g) = plot(ax, nan, nan, 'o', ...
        'MarkerFaceColor', group_colors(g, :), ...
        'MarkerEdgeColor', group_colors(g, :), ...
        'LineStyle', 'none', ...
        'MarkerSize', 7);
end

legend(ax, dummy, M.labels.group_short, ...
    'Location', 'eastoutside', ...
    'Interpreter', 'none', ...
    'Box', 'off');

title(ax, sprintf('%s | %s | %s | %s slope (%s regression)', ...
    M.meta.effect_type, M.meta.data_content, M.meta.model_mode, ...
    M.meta.metric_name, M.meta.regression_type_for_slope), ...
    'Interpreter', 'none', ...
    'FontWeight', 'bold');

ylabel(ax, sprintf('Slope (%s)', M.meta.regression_type_for_slope), ...
    'Interpreter', 'none');

xlabel(ax, 'Comparison', 'Interpreter', 'none');
cleanAxis(ax);
end

function layout = computeSlopeLayout(nComparisons, nGroups)
group_step = 0.82;
comparison_gap = 1.05;

group_x = nan(nComparisons, nGroups);
comparison_center = nan(1, nComparisons);
separator_x = nan(1, max(0, nComparisons - 1));

x = 1;

for c = 1:nComparisons
    first_x = x;

    for g = 1:nGroups
        group_x(c, g) = x;
        x = x + group_step;
    end

    last_x = group_x(c, nGroups);
    comparison_center(c) = mean([first_x, last_x]);

    if c < nComparisons
        separator_x(c) = last_x + comparison_gap / 2;
    end

    x = x + comparison_gap;
end

layout.group_x = group_x;
layout.comparison_center = comparison_center;
layout.separator_x = separator_x;
layout.x_min = min(group_x(:)) - 0.7;
layout.x_max = max(group_x(:)) + 0.7;
end

function applySlopeAxisFormatting(ax, M, layout, values)
nComparisons = size(values, 2);

x_ticks = reshape(layout.group_x', 1, []);
tick_labels = repmat(M.labels.group_short(:)', 1, nComparisons);

set(ax, 'XTick', x_ticks, ...
    'XTickLabel', tick_labels, ...
    'TickLabelInterpreter', 'none');

xlim(ax, [layout.x_min, layout.x_max]);
ylim(ax, computeSignedYLimits(values(:)));

yl = ylim(ax);
yr = diff(yl);

for c = 1:nComparisons
    text(ax, layout.comparison_center(c), yl(1) - 0.105 * yr, ...
        M.labels.comparison{c}, ...
        'HorizontalAlignment', 'center', ...
        'VerticalAlignment', 'top', ...
        'Interpreter', 'none', ...
        'FontSize', 10, ...
        'Clipping', 'off');
end

for c = 1:numel(layout.separator_x)
    plot(ax, [layout.separator_x(c), layout.separator_x(c)], yl, ...
        '-', 'Color', [0.75 0.75 0.75], ...
        'LineWidth', 0.8, ...
        'HandleVisibility', 'off');
end

set(ax, 'Clipping', 'off');
end

function hfig = plotDeltaSummary( ...
    M, fig_visible, plot_style, group_colors_base, ...
    session_color_lightness_start, session_color_lightness_end, ...
    delta_sign_mode, ...
    point_size, point_alpha, ...
    bar_alpha, bar_value_mode, show_summary_marker, point_jitter_width, ...
    violin_alpha, show_mean_marker, show_median_line, ...
    draw_zero_line, zero_line_style, zero_line_width, ...
    use_broken_axis_for_delta, ...
    delta_break_start_prctile, ...
    delta_broken_axis_trigger_ratio, ...
    delta_tail_display_frac, ...
    delta_break_gap_frac, ...
    delta_min_tail_display_slope, ...
    draw_delta_broken_axis_marks, ...
    fig_width_min, fig_height, max_fig_width)

switch char(delta_sign_mode)
    case 'positive'
        delta_values = M.values.delta_positive_base;
        fig_name = 'Session delta summary: baseline >= 0';
        title_sign = 'base >= 0';
        ylabel_text = 'Delta, base >= 0';

    case 'negative'
        delta_values = M.values.delta_negative_base;
        fig_name = 'Session delta summary: baseline < 0';
        title_sign = 'base < 0';
        ylabel_text = 'Delta, base < 0';

    otherwise
        error('Unknown delta_sign_mode: %s', delta_sign_mode);
end

nSessions = size(delta_values, 1);
nComparisons = size(delta_values, 2);
nGroups = size(delta_values, 3);

layout = computeDeltaLayout(nComparisons, nGroups, nSessions);

fig_width = min(max_fig_width, ...
    max(fig_width_min, 90 * nComparisons * nGroups * nSessions + 240));

hfig = figure('Visible', fig_visible, ...
    'Color', 'w', ...
    'Position', [100 100 fig_width fig_height], ...
    'Name', fig_name);

ax = axes(hfig);
hold(ax, 'on');

set(ax, 'Units', 'normalized');
set(ax, 'Position', [0.055 0.25 0.92 0.66]);

group_colors = resolveGroupColors(group_colors_base, nGroups);
session_colors = makeSessionColorsByGroup( ...
    group_colors, nSessions, ...
    session_color_lightness_start, session_color_lightness_end);

num_items = nComparisons * nGroups * nSessions;
bar_width = computeAdaptiveItemWidth(num_items, 0.18, 0.52);
violin_width = computeAdaptiveItemWidth(num_items, 0.14, 0.42);

all_values = collectAllDeltaValues(delta_values);

delta_axis_info = computeSignedBrokenAxisInfo( ...
    all_values, ...
    use_broken_axis_for_delta, ...
    delta_break_start_prctile, ...
    delta_broken_axis_trigger_ratio, ...
    delta_tail_display_frac, ...
    delta_break_gap_frac, ...
    delta_min_tail_display_slope);

for c = 1:nComparisons
    for g = 1:nGroups
        for s = 1:nSessions
            x0 = layout.session_x(c, g, s);
            y = delta_values{s, c, g};
            color = squeeze(session_colors(g, s, :))';

            switch char(plot_style)
                case 'bar_points'
                    drawBarWithPoints(ax, x0, y, bar_width, color, ...
                        point_size, point_alpha, bar_alpha, ...
                        point_jitter_width, bar_value_mode, show_summary_marker, delta_axis_info);

                case 'violin'
                    drawViolinWithPoints(ax, x0, y, violin_width, color, ...
                        point_size, point_alpha, violin_alpha, ...
                        show_mean_marker, show_median_line, delta_axis_info);

                otherwise
                    error('Unknown plot_style: %s', plot_style);
            end
        end
    end
end

if draw_zero_line
    zero_plot = brokenTransformSigned(0, delta_axis_info);
    plot(ax, [layout.x_min, layout.x_max], [zero_plot, zero_plot], ...
        zero_line_style, ...
        'LineWidth', zero_line_width, ...
        'HandleVisibility', 'off');
end

applyDeltaAxisFormatting(ax, M, layout, delta_axis_info);

if delta_axis_info.use_broken_axis && draw_delta_broken_axis_marks
    drawYBrokenAxisMarks(ax, delta_axis_info);
end

title(ax, sprintf('%s | %s | %s | %s delta (%s)', ...
    M.meta.effect_type, M.meta.data_content, M.meta.model_mode, ...
    M.meta.metric_name, title_sign), ...
    'Interpreter', 'none', ...
    'FontWeight', 'bold');

ylabel(ax, ylabel_text, 'Interpreter', 'none');
xlabel(ax, '', 'Interpreter', 'none');

cleanAxis(ax);
end

function all_values = collectAllDeltaValues(delta_values)
all_values = [];

for i = 1:numel(delta_values)
    y = delta_values{i};
    y = y(:);
    y = y(isfinite(y));
    all_values = [all_values; y]; %#ok<AGROW>
end
end

function layout = computeDeltaLayout(nComparisons, nGroups, nSessions)
session_step = 0.78;
group_gap = 0.70;
comparison_gap = 1.25;

session_x = nan(nComparisons, nGroups, nSessions);
group_center = nan(nComparisons, nGroups);
comparison_center = nan(1, nComparisons);
separator_x = nan(1, max(0, nComparisons - 1));

x = 1;

for c = 1:nComparisons
    comp_first = x;

    for g = 1:nGroups
        group_first = x;

        for s = 1:nSessions
            session_x(c, g, s) = x;
            x = x + session_step;
        end

        group_last = session_x(c, g, nSessions);
        group_center(c, g) = mean([group_first, group_last]);

        if g < nGroups
            x = x + group_gap;
        end
    end

    comp_last = session_x(c, nGroups, nSessions);
    comparison_center(c) = mean([comp_first, comp_last]);

    if c < nComparisons
        separator_x(c) = comp_last + comparison_gap / 2;
    end

    x = x + comparison_gap;
end

layout.session_x = session_x;
layout.group_center = group_center;
layout.comparison_center = comparison_center;
layout.separator_x = separator_x;
layout.x_min = min(session_x(:)) - 0.7;
layout.x_max = max(session_x(:)) + 0.7;
end

function applyDeltaAxisFormatting(ax, M, layout, axis_info)
nSessions = M.meta.num_sessions;
nComparisons = M.meta.num_comparisons;
nGroups = M.meta.num_groups;

x_ticks = [];
tick_labels = {};

for c = 1:nComparisons
    for g = 1:nGroups
        for s = 1:nSessions
            x_ticks(end+1) = layout.session_x(c, g, s); %#ok<AGROW>
            tick_labels{end+1} = M.sessions.included(s).session_label; %#ok<AGROW>
        end
    end
end

set(ax, 'XTick', x_ticks, ...
    'XTickLabel', tick_labels, ...
    'TickLabelInterpreter', 'none');

xlim(ax, [layout.x_min, layout.x_max]);
ylim(ax, [axis_info.plot_axis_min, axis_info.plot_axis_max]);

set(ax, 'YTick', axis_info.plot_ticks, ...
    'YTickLabel', axis_info.tick_labels, ...
    'TickLabelInterpreter', 'none');

yl = ylim(ax);
yr = diff(yl);

group_text_y = yl(1) - 0.080 * yr;
comparison_text_y = yl(1) - 0.165 * yr;

for c = 1:nComparisons
    for g = 1:nGroups
        text(ax, layout.group_center(c, g), group_text_y, ...
            M.labels.group_short{g}, ...
            'HorizontalAlignment', 'center', ...
            'VerticalAlignment', 'top', ...
            'Interpreter', 'none', ...
            'FontSize', 9, ...
            'Clipping', 'off');
    end

    text(ax, layout.comparison_center(c), comparison_text_y, ...
        M.labels.comparison{c}, ...
        'HorizontalAlignment', 'center', ...
        'VerticalAlignment', 'top', ...
        'Interpreter', 'none', ...
        'FontSize', 10, ...
        'Clipping', 'off');
end

for c = 1:numel(layout.separator_x)
    plot(ax, [layout.separator_x(c), layout.separator_x(c)], yl, ...
        '-', 'Color', [0.75 0.75 0.75], ...
        'LineWidth', 0.8, ...
        'HandleVisibility', 'off');
end

set(ax, 'Clipping', 'off');
end

function w = computeAdaptiveItemWidth(num_items, min_w, max_w)
if num_items <= 0
    w = max_w;
    return;
end

w = 18 / max(num_items, 1);
w = max(min_w, min(max_w, w));
end

function colors = resolveGroupColors(group_colors_base, nGroups)
colors = zeros(nGroups, 3);

for g = 1:nGroups
    if g <= size(group_colors_base, 1)
        colors(g, :) = group_colors_base(g, :);
    else
        colors(g, :) = [0 0 0];
    end
end
end

function session_colors = makeSessionColorsByGroup( ...
    group_colors, nSessions, light_start, light_end)

nGroups = size(group_colors, 1);
session_colors = nan(nGroups, nSessions, 3);

if nSessions == 1
    lightness = light_end;
else
    lightness = linspace(light_start, light_end, nSessions);
end

for g = 1:nGroups
    base = group_colors(g, :);

    for s = 1:nSessions
        f = lightness(s);
        c = (1 - f) * base + f * [1 1 1];
        session_colors(g, s, :) = c;
    end
end
end

function axis_info = makeLinearAxisInfo()
axis_info = struct();
axis_info.use_broken_axis = false;
axis_info.raw_axis_min = NaN;
axis_info.raw_axis_max = NaN;
axis_info.raw_abs_max = NaN;
axis_info.break_start = NaN;
axis_info.break_end = NaN;
axis_info.break_gap = 0;
axis_info.tail_display_len = 0;
axis_info.plot_axis_min = NaN;
axis_info.plot_axis_max = NaN;
axis_info.plot_ticks = [];
axis_info.tick_labels = {};
end

function drawBarWithPoints(ax, x0, y, width, color, point_size, point_alpha, ...
    bar_alpha, point_jitter_width, bar_value_mode, show_summary_marker, axis_info)

y = y(:);
y = y(isfinite(y));

if isempty(y)
    return;
end

meanVal = mean(y, 'omitnan');
medianVal = median(y, 'omitnan');

switch char(bar_value_mode)
    case 'mean'
        barVal = meanVal;
        markerVal = medianVal;
        markerShape = 's';

    case 'median'
        barVal = medianVal;
        markerVal = meanVal;
        markerShape = 's';

    otherwise
        error('Unknown bar_value_mode: %s', bar_value_mode);
end

barPlot = brokenTransformSigned(barVal, axis_info);
markerPlot = brokenTransformSigned(markerVal, axis_info);
zeroPlot = brokenTransformSigned(0, axis_info);
yPlot = brokenTransformSigned(y, axis_info);

hb = bar(ax, x0, barPlot, width, ...
    'FaceColor', color, ...
    'EdgeColor', color, ...
    'LineWidth', 0.8, ...
    'HandleVisibility', 'off');

try
    hb.BaseValue = zeroPlot;
catch
end

try
    hb.FaceAlpha = bar_alpha;
catch
end

if point_jitter_width > 0
    jitter = (rand(size(yPlot)) - 0.5) * point_jitter_width;
else
    jitter = zeros(size(yPlot));
end

try
    scatter(ax, x0 + jitter, yPlot, point_size, ...
        'MarkerFaceColor', color, ...
        'MarkerEdgeColor', 'k', ...
        'MarkerFaceAlpha', point_alpha, ...
        'MarkerEdgeAlpha', point_alpha, ...
        'HandleVisibility', 'off');
catch
    scatter(ax, x0 + jitter, yPlot, point_size, ...
        'MarkerFaceColor', color, ...
        'MarkerEdgeColor', 'k', ...
        'HandleVisibility', 'off');
end

if show_summary_marker
    plot(ax, x0, markerPlot, markerShape, ...
        'MarkerSize', 6, ...
        'MarkerEdgeColor', 'k', ...
        'MarkerFaceColor', 'k', ...
        'LineWidth', 0.8, ...
        'HandleVisibility', 'off');
end
end

function drawViolinWithPoints(ax, x0, y, width, color, point_size, point_alpha, ...
    violin_alpha, show_mean_marker, show_median_line, axis_info)

y = y(:);
y = y(isfinite(y));

if isempty(y)
    return;
end

if numel(y) >= 2 && (max(y) - min(y)) > eps
    [dens, yi] = estimateDensity(y);

    if ~isempty(dens) && max(dens) > 0
        dens = dens ./ max(dens) * width;
        yiPlot = brokenTransformSigned(yi, axis_info);

        patch(ax, [x0 - dens, fliplr(x0 + dens)], ...
            [yiPlot, fliplr(yiPlot)], color, ...
            'FaceAlpha', violin_alpha, ...
            'EdgeColor', color, ...
            'LineWidth', 0.8, ...
            'HandleVisibility', 'off');
    end
else
    yOne = brokenTransformSigned(y(1), axis_info);

    plot(ax, [x0 - width, x0 + width], [yOne, yOne], '-', ...
        'Color', color, ...
        'LineWidth', 1.4, ...
        'HandleVisibility', 'off');
end

yPlot = brokenTransformSigned(y, axis_info);
jitter = (rand(size(yPlot)) - 0.5) * width * 0.95;

try
    scatter(ax, x0 + jitter, yPlot, point_size, ...
        'MarkerFaceColor', color, ...
        'MarkerEdgeColor', 'k', ...
        'MarkerFaceAlpha', point_alpha, ...
        'MarkerEdgeAlpha', point_alpha, ...
        'HandleVisibility', 'off');
catch
    scatter(ax, x0 + jitter, yPlot, point_size, ...
        'MarkerFaceColor', color, ...
        'MarkerEdgeColor', 'k', ...
        'HandleVisibility', 'off');
end

if show_median_line
    medVal = median(y, 'omitnan');
    medPlot = brokenTransformSigned(medVal, axis_info);

    plot(ax, [x0 - width * 0.72, x0 + width * 0.72], ...
        [medPlot, medPlot], ...
        'k-', ...
        'LineWidth', 1.0, ...
        'HandleVisibility', 'off');
end

if show_mean_marker
    meanVal = mean(y, 'omitnan');
    meanPlot = brokenTransformSigned(meanVal, axis_info);

    plot(ax, x0, meanPlot, 'kd', ...
        'MarkerSize', 5, ...
        'MarkerFaceColor', 'w', ...
        'LineWidth', 0.8, ...
        'HandleVisibility', 'off');
end
end

function [dens, yi] = estimateDensity(y)
y = y(:)';

if numel(y) < 2 || (max(y) - min(y)) <= eps
    dens = [];
    yi = [];
    return;
end

if exist('ksdensity', 'file') == 2
    try
        [dens, yi] = ksdensity(y, 'NumPoints', 80);
        dens = dens(:)';
        yi = yi(:)';
        return;
    catch
    end
end

nBins = min(24, max(6, round(sqrt(numel(y)) * 2)));
edges = linspace(min(y), max(y), nBins + 1);
counts = histcounts(y, edges);
centers = (edges(1:end-1) + edges(2:end)) / 2;

if numel(counts) >= 3
    kernel = [1 2 3 2 1];
    kernel = kernel / sum(kernel);
    counts = conv(counts, kernel, 'same');
end

yi = linspace(min(y), max(y), 80);
dens = interp1(centers, counts, yi, 'linear', 0);
end

function axis_info = computeSignedBrokenAxisInfo( ...
    values, use_broken_axis, break_start_prctile, ...
    trigger_ratio, tail_display_frac, break_gap_frac, min_tail_display_slope)

values = values(:);
values = values(isfinite(values));

axis_info = struct();
axis_info.use_broken_axis = false;
axis_info.break_start_prctile = break_start_prctile;
axis_info.trigger_ratio = trigger_ratio;
axis_info.tail_display_frac = tail_display_frac;
axis_info.break_gap_frac = break_gap_frac;
axis_info.min_tail_display_slope = min_tail_display_slope;
axis_info.raw_axis_min = NaN;
axis_info.raw_axis_max = NaN;
axis_info.raw_abs_max = NaN;
axis_info.break_start = NaN;
axis_info.break_end = NaN;
axis_info.break_gap = 0;
axis_info.tail_display_len = 0;
axis_info.plot_axis_min = NaN;
axis_info.plot_axis_max = NaN;
axis_info.plot_ticks = [];
axis_info.tick_labels = {};

if isempty(values)
    axis_info.raw_axis_min = -1;
    axis_info.raw_axis_max = 1;
    axis_info.raw_abs_max = 1;
    axis_info.break_start = 1;
    axis_info.break_end = 1;
    axis_info.plot_axis_min = -1;
    axis_info.plot_axis_max = 1;
    [axis_info.plot_ticks, axis_info.tick_labels] = buildLinearTicksAndLabels(-1, 1);
    return;
end

raw_min = min([values; 0]);
raw_max = max([values; 0]);
raw_abs_max = max(abs([raw_min, raw_max]));

if raw_abs_max <= 0 || ~isfinite(raw_abs_max)
    raw_abs_max = 1;
end

axis_info.raw_axis_min = raw_min;
axis_info.raw_axis_max = raw_max;
axis_info.raw_abs_max = raw_abs_max;

abs_vals = abs(values);
abs_vals = abs_vals(isfinite(abs_vals));

break_start = percentile_local(abs_vals, break_start_prctile);

if isempty(break_start) || ~isfinite(break_start) || break_start <= 0
    break_start = raw_abs_max;
end

do_broken = use_broken_axis && ...
    raw_abs_max > break_start * trigger_ratio && ...
    break_start > 0;

if ~do_broken
    axis_info.use_broken_axis = false;
    axis_info.break_start = raw_abs_max;
    axis_info.break_end = raw_abs_max;
    axis_info.break_gap = 0;
    axis_info.tail_display_len = 0;

    pad = 0.08 * max(eps, raw_max - raw_min);
    axis_info.plot_axis_min = raw_min - pad;
    axis_info.plot_axis_max = raw_max + pad;

    [axis_info.plot_ticks, axis_info.tick_labels] = ...
        buildLinearTicksAndLabels(axis_info.plot_axis_min, axis_info.plot_axis_max);

    return;
end

high_abs_vals = abs_vals(abs_vals > break_start);
break_end = min(high_abs_vals);

if isempty(break_end) || ~isfinite(break_end) || break_end <= break_start
    break_end = break_start;
end

raw_tail_span = max(eps, raw_abs_max - break_end);
tail_display_len_from_frac = max(eps, break_start * tail_display_frac);
tail_display_len_from_slope = raw_tail_span * min_tail_display_slope;
tail_display_len = max(tail_display_len_from_frac, tail_display_len_from_slope);
break_gap = max(eps, break_start * break_gap_frac);

axis_info.use_broken_axis = true;
axis_info.break_start = break_start;
axis_info.break_end = break_end;
axis_info.break_gap = break_gap;
axis_info.tail_display_len = tail_display_len;

plot_min = brokenTransformSigned(raw_min, axis_info);
plot_max = brokenTransformSigned(raw_max, axis_info);

pad = 0.08 * max(eps, plot_max - plot_min);

axis_info.plot_axis_min = plot_min - pad;
axis_info.plot_axis_max = plot_max + pad;

[axis_info.plot_ticks, axis_info.tick_labels] = buildBrokenTicksAndLabels(axis_info);
end

function x_plot = brokenTransformSigned(x_raw, axis_info)
x_plot = x_raw;

if ~isfield(axis_info, 'use_broken_axis') || ~axis_info.use_broken_axis
    return;
end

sgn = sign(x_raw);
ax = abs(x_raw);

break_start = axis_info.break_start;
break_end = axis_info.break_end;
raw_abs_max = axis_info.raw_abs_max;
tail_display_len = axis_info.tail_display_len;
break_gap = axis_info.break_gap;

x_plot_abs = ax;

gap_mask = ax > break_start & ax < break_end;
tail_mask = ax >= break_end;

if break_end > break_start
    x_plot_abs(gap_mask) = break_start ...
        + (ax(gap_mask) - break_start) ./ (break_end - break_start) .* break_gap;
else
    x_plot_abs(gap_mask) = break_start + break_gap;
end

if raw_abs_max > break_end
    x_plot_abs(tail_mask) = break_start + break_gap ...
        + (ax(tail_mask) - break_end) ./ (raw_abs_max - break_end) .* tail_display_len;
else
    x_plot_abs(tail_mask) = break_start + break_gap + tail_display_len;
end

x_plot = sgn .* x_plot_abs;
end

function [ticks, labels] = buildLinearTicksAndLabels(axis_min, axis_max)
if ~isfinite(axis_min) || ~isfinite(axis_max) || axis_min == axis_max
    axis_min = -1;
    axis_max = 1;
end

ticks = linspace(axis_min, axis_max, 5);
ticks(abs(ticks) < 1e-12) = 0;
labels = composeNumericTickLabels(ticks);
end

function [plot_ticks, tick_labels] = buildBrokenTicksAndLabels(axis_info)
raw_ticks = choosePrebreakTicksSigned(axis_info.break_start);

raw_ticks = raw_ticks(raw_ticks >= axis_info.raw_axis_min & ...
    raw_ticks <= axis_info.raw_axis_max);

if ~any(abs(raw_ticks) < 1e-12)
    raw_ticks = sort([raw_ticks, 0]);
end

raw_ticks = uniqueWithTolerance(raw_ticks, 1e-10);
plot_ticks = brokenTransformSigned(raw_ticks, axis_info);
tick_labels = composeNumericTickLabels(raw_ticks);
end

function raw_ticks = choosePrebreakTicksSigned(prebreak_abs_max)
if isempty(prebreak_abs_max) || ~isfinite(prebreak_abs_max) || prebreak_abs_max <= 0
    raw_ticks = 0;
    return;
end

target_intervals = 4;
rough_step = (2 * prebreak_abs_max) / target_intervals;
step = chooseNiceNumericStep(rough_step);

if step <= 0 || ~isfinite(step)
    raw_ticks = linspace(-prebreak_abs_max, prebreak_abs_max, 5);
    raw_ticks(abs(raw_ticks) < 1e-12) = 0;
    return;
end

max_tick = floor(prebreak_abs_max / step) * step;

if max_tick <= 0
    raw_ticks = [-prebreak_abs_max, 0, prebreak_abs_max];
else
    raw_ticks = -max_tick:step:max_tick;

    if ~any(abs(raw_ticks) < 1e-12)
        raw_ticks = sort([raw_ticks, 0]);
    end
end

raw_ticks(abs(raw_ticks) < 1e-12) = 0;
end

function step = chooseNiceNumericStep(rough_step)
if rough_step <= 0 || ~isfinite(rough_step)
    step = 1;
    return;
end

exponent = floor(log10(rough_step));
base = 10 ^ exponent;
candidates = [1 2 2.5 5 10] * base;
candidates = candidates(candidates >= rough_step);

if isempty(candidates)
    step = 10 * base;
else
    step = candidates(1);
end
end

function vals_unique = uniqueWithTolerance(vals, tol)
vals = vals(:)';
vals_unique = [];

for i = 1:numel(vals)
    if isempty(vals_unique) || all(abs(vals(i) - vals_unique) > tol)
        vals_unique(end+1) = vals(i); %#ok<AGROW>
    end
end
end

function labels = composeNumericTickLabels(vals)
labels = cell(size(vals));

for i = 1:numel(vals)
    v = vals(i);

    if abs(v) < 1e-12
        v = 0;
    end

    if abs(v) >= 1000 || (abs(v) > 0 && abs(v) < 0.001)
        labels{i} = sprintf('%.2g', v);
    elseif abs(v - round(v)) < 1e-10
        labels{i} = sprintf('%d', round(v));
    else
        labels{i} = sprintf('%.3g', v);
    end
end
end

function drawYBrokenAxisMarks(ax, axis_info)
if ~axis_info.use_broken_axis
    return;
end

xLim = ax.XLim;
yLim = ax.YLim;

xSpan = max(eps, diff(xLim));
ySpan = max(eps, diff(yLim));

% Use x-axis scale only for horizontal slash width,
% and y-axis scale only for vertical slash height.
% Do not use max(xSpan, ySpan), otherwise a wide x-axis makes the
% y-axis break marks extremely large.
slash_dx = xSpan * 0.006;
slash_dy = ySpan * 0.018;
offset_y = ySpan * 0.018;

x0 = xLim(1);

break_center_abs = axis_info.break_start + axis_info.break_gap / 2;

y_centers = [];

if axis_info.raw_axis_max > axis_info.break_start
    y_centers(end+1) = break_center_abs; 
end

if axis_info.raw_axis_min < -axis_info.break_start
    y_centers(end+1) = -break_center_abs; 
end

for i = 1:numel(y_centers)
    yc = y_centers(i);

    % First slash.
    plot(ax, ...
        [x0 - slash_dx, x0 + slash_dx], ...
        [yc - slash_dy, yc + slash_dy], ...
        'k-', ...
        'LineWidth', 1.0, ...
        'Clipping', 'off', ...
        'HandleVisibility', 'off');

    % Second slash.
    plot(ax, ...
        [x0 - slash_dx, x0 + slash_dx], ...
        [yc - slash_dy + offset_y, yc + slash_dy + offset_y], ...
        'k-', ...
        'LineWidth', 1.0, ...
        'Clipping', 'off', ...
        'HandleVisibility', 'off');
end
end

function q = percentile_local(x, p)
x = x(:);
x = x(isfinite(x));

if isempty(x)
    q = NaN;
    return;
end

x = sort(x);
n = numel(x);

if n == 1
    q = x;
    return;
end

p = max(0, min(100, p));
pos = 1 + (n - 1) * p / 100;

lo = floor(pos);
hi = ceil(pos);

if lo == hi
    q = x(lo);
else
    w = pos - lo;
    q = (1 - w) * x(lo) + w * x(hi);
end
end

function yLim = computeSignedYLimits(values)
values = values(:);
values = values(isfinite(values));

if isempty(values)
    yLim = [-1 1];
    return;
end

vmin = min(values);
vmax = max(values);

vmin = min(vmin, 0);
vmax = max(vmax, 0);

if abs(vmax - vmin) < eps
    if vmax == 0
        yLim = [-1 1];
    else
        pad = abs(vmax) * 0.1;
        yLim = [vmin - pad, vmax + pad];
    end

    return;
end

pad = 0.10 * (vmax - vmin);
yLim = [vmin - pad, vmax + pad];
end

function cleanAxis(ax)
grid(ax, 'on');
box(ax, 'off');

set(ax, ...
    'TickDir', 'out', ...
    'LineWidth', 1, ...
    'FontSize', 11);
end

function label = makeComparisonLabel(baseline_field, comparation_field)
label = sprintf('%s v %s', ...
    shortFieldLabel(comparation_field), ...
    shortFieldLabel(baseline_field));
end

function label = shortFieldLabel(field_name)
switch char(field_name)
    case 'y'
        label = 'y';

    case 'd'
        label = 'd';

    case 'yRecon_use_all'
        label = 'all';

    case 'yRecon_use_all_no_d'
        label = 'all no d';

    case 'yRecon_use_across'
        label = 'acr';

    case 'yRecon_use_across_no_d'
        label = 'acr no d';

    case 'yRecon_use_within'
        label = 'win';

    case 'yRecon_use_within_no_d'
        label = 'win no d';

    case 'yRecon_across_excl_within'
        label = 'acr excl win';

    case 'yRecon_within_excl_across'
        label = 'win excl acr';

    case 'yRecon_use_feedback'
        label = 'fb';

    case 'yRecon_feedback_excl_within_ff_ambiguous'
        label = 'fb excl win ff amb';

    case 'yRecon_feedback_excl_within'
        label = 'fb excl win';

    case 'yRecon_feedback_excl_ff_ambiguous'
        label = 'fb excl ff amb';

    case 'yRecon_use_feedforward'
        label = 'ff';

    case 'yRecon_feedforward_excl_within_fb_ambiguous'
        label = 'ff excl win fb amb';

    case 'yRecon_feedforward_excl_within'
        label = 'ff excl win';

    case 'yRecon_feedforward_excl_fb_ambiguous'
        label = 'ff excl fb amb';

    case 'yRecon_use_all_with_R'
        label = 'all R';

    case 'yRecon_use_across_with_R'
        label = 'acr R';

    case 'yRecon_use_within_with_R'
        label = 'win R';

    case 'yRecon_across_excl_within_with_R'
        label = 'acr excl win R';

    case 'yRecon_within_excl_across_with_R'
        label = 'win excl acr R';

    case 'yRecon_use_all_keep_resid'
        label = 'all KR';

    case 'yRecon_use_across_keep_resid'
        label = 'acr KR';

    case 'yRecon_use_within_keep_resid'
        label = 'win KR';

    case 'yRecon_across_excl_within_keep_resid'
        label = 'acr excl win KR';

    case 'yRecon_within_excl_across_keep_resid'
        label = 'win excl acr KR';

    otherwise
        label = fallbackShortFieldLabel(field_name);
end
end

function label = fallbackShortFieldLabel(field_name)
label = char(field_name);

label = strrep(label, 'yRecon_', '');
label = strrep(label, 'use_', '');
label = strrep(label, 'across', 'acr');
label = strrep(label, 'within', 'win');
label = strrep(label, 'excl', 'excl');
label = strrep(label, 'feedback', 'fb');
label = strrep(label, 'feedforward', 'ff');
label = strrep(label, 'ambiguous', 'amb');
label = strrep(label, 'condition', 'cond');
label = strrep(label, 'residual', 'resid');
label = strrep(label, 'resid', 'res');
label = strrep(label, '_', ' ');
label = regexprep(label, '\s+', ' ');
label = strtrim(label);
end

function savePngLocal(fig, pngFile, dpi)
drawnow;

try
    if exist('exportgraphics', 'file') == 2
        exportgraphics(fig, pngFile, ...
            'Resolution', dpi, ...
            'BackgroundColor', 'white');
    else
        set(fig, 'PaperPositionMode', 'auto');
        print(fig, pngFile, '-dpng', sprintf('-r%d', dpi));
    end
catch
    warning('exportgraphics/print failed. Falling back to saveas.');
    saveas(fig, pngFile);
end
end